const body = $input.first().json.body || $input.first().json;
const db06_id = (body.db06_id || body.id || '').toString().replace(/-/g, '');
if (!db06_id) throw new Error('missing db06_id');
return [{ json: { db06_id } }];

const p = $input.first().json;
const TARGET_RELS = ["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"];
let target_id='',target_rel='';
for (const rel of TARGET_RELS){ const a=p.properties[rel]?.relation||[]; if(a.length){ target_id=(a[0].id||'').replace(/-/g,''); target_rel=rel; break; } }
return [{ json: {
  db06_id: p.id.replace(/-/g,''),
  ai_mode: p.properties['ai模式']?.select?.name || '分析',
  exec_idea: p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '',
  db05_id: target_id, target_rel,
  sort_num: p.properties['排序']?.number
}}];

