const refs = ($('Query 資料參考').first().json.results)||[];
const target = $input.first().json;
const item = $('Parse DB06').first().json;
const tprops = target.properties||{};
const _tp = Object.values(tprops).find(v=>v&&v.type==='title');
const target_name = (_tp?.title||[]).map(t=>t.plain_text).join('') || '(未命名)';
const target_idea = tprops['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '';
const corpus = refs.map((p,i)=>{ const pr=p.properties||{}; const nm=(pr['明細名稱']?.title||[]).map(t=>t.plain_text).join(''); const sm=(pr['簡介摘要']?.rich_text||[]).map(t=>t.plain_text).join(''); const ct=(pr['明細內容']?.rich_text||[]).map(t=>t.plain_text).join(''); return (i+1)+'. '+nm+'
'+((sm||ct).slice(0,700)); }).join('

');
const system = '你是 makesense（現思文化）嗨嗨家族的分析棒。職責:讀搜查棒採集的外部參考資料,做認知分析。
工作:
1. 通讀全部資料,抽出具名詞彙(人物/機構/地點/事件/法規/計畫名)。
2. 抽出關鍵數據(金額/坪數/年度/比率/筆數等可查證數字)。
3. 寫一段分析備註:這批資料對本案(經費估算)的整體啟示、可用重點、缺口。
鐵律:只根據資料寫,不臆測;繁體中文;具名詞彙要精確。
只回合法 JSON,最後一個區塊:
{"分析備註":"200-500字整體分析","具名詞彙":["..."],"關鍵數據":["項目=數值"],"execution_summary":"做了什麼"}';
const user = 'target 內容
名稱 '+target_name+'
本棒執行構想
'+(item.exec_idea||target_idea||'(空)')+'

搜查棒採集的 '+refs.length+' 筆參考資料:
'+corpus+'

請分析,回 JSON。';
return [{ json: { system, user, db06_id:item.db06_id, db05_id:item.db05_id, ai_mode:item.ai_mode, sort_num:item.sort_num, ref_count:refs.length } }];

const resp = $input.first().json;
const text = resp.content?.[0]?.text || '';
const usage = resp.usage || {};
const prompt = $('Build analyze prompt').first().json;
let parsed;
try { const m=text.match(/\{[\s\S]*\}/); parsed = m?JSON.parse(m[0]):{ '分析備註': text.slice(0,500) }; }
catch(e){ parsed = { '分析備註': 'JSON parse failed: '+text.slice(0,300) }; }
const sanitize = s => (s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g,' ').replace(/[\u2010-\u2027\u2030-\u205E]/g,' ').replace(/[\uFF00-\uFF0F\uFF1A-\uFF20\uFF3B-\uFF40\uFF5B-\uFF65]/g,' ').replace(/[\u3000-\u3017\u301D-\u303F]/g,' ').replace(/\s+/g,' ').trim().slice(0,600);
const it=parseInt(usage.input_tokens||0), ot=parseInt(usage.output_tokens||0), cr=parseInt(usage.cache_read_input_tokens||0), cw=parseInt(usage.cache_creation_input_tokens||0);
const cost=((it*3+ot*15+cw*3.75+cr*0.30)/1000000*32).toFixed(2);
const usage_line='進='+it+' 出='+ot+' 成本NT'+cost;
const fenxi=(parsed['分析備註']||'').toString();
const terms=Array.isArray(parsed['具名詞彙'])?parsed['具名詞彙']:[];
const data=Array.isArray(parsed['關鍵數據'])?parsed['關鍵數據']:[];
let full=fenxi;
if(terms.length) full+='\n\n[具名詞彙] '+terms.join('、');
if(data.length) full+='\n[關鍵數據] '+data.join('；');
full=full.slice(0,1900);
const summary=(parsed['execution_summary']||'分析完成')+' 抽出具名詞彙 '+terms.length+' 個 關鍵數據 '+data.length+' 項';
return [{ json: { db06_id:prompt.db06_id, db05_id:prompt.db05_id, ai_mode:prompt.ai_mode, sort_num:prompt.sort_num, ref_count:prompt.ref_count, fenxi_full:full, terms_n:terms.length, data_n:data.length, usage_line, safe_summary:sanitize(summary), preview_text:('分析備註已寫入 '+full.length+' 字'), validator_warning:'' } }];

const row = $input.first().json || {};
const pc = $('Parse Claude').first().json;
const auto_mode = row.auto_mode === true;
const reply_to = parseInt(row.last_msg_id || 0) || 0;
const base = '關卡B 成果確認
第 ' + (pc.sort_num != null ? pc.sort_num : '?') + ' 棒 (' + pc.ai_mode + ') 已完成。
DB06 頁面 ' + pc.db06_id + '

執行備註:
' + pc.safe_summary + '

' + pc.preview_text + (pc.validator_warning || '') + '
tokens ' + pc.usage_line;
const manual_msg = base + '

按 OK 進下一棒,按 OK ALL 之後全自動。要 redo 重跑請打字 reply。
gateB db06=' + pc.db06_id;
const auto_msg = base + '

[全自動模式] 自動進下一棒,免按。';
return [{ json: { auto_mode, reply_to, flow_id: pc.db05_id, db05_id: pc.db05_id, db06_id: pc.db06_id, sort_num: pc.sort_num, ai_mode: pc.ai_mode, manual_msg, auto_msg, cb_ok: 'B1:' + pc.db06_id, cb_all: 'BA:' + pc.db06_id } }];

